class Solution:
    def minOperations(self, k: int) -> int:
        if k == 1:
            return 0
        # We try different numbers of duplications and calculate the required increments
        min_ops = float('inf')
        for dup in range(1, int(k**0.5) + 2):
            # After dup duplications, we have (dup + 1) elements
            # Each element needs to be at least ceil(k / (dup + 1))
            inc = (k + dup) // (dup + 1) - 1
            total_ops = inc + dup
            min_ops = min(min_ops, total_ops)
        return min_ops
